from flask import Flask, request, jsonify
from onelogin.saml2.auth import OneLogin_Saml2_Auth
from onelogin.saml2.settings import OneLogin_Saml2_Settings
import os
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)

# Load SAML settings
def prepare_flask_request():
    return {
        'http_host': request.host,
        'server_port': request.environ.get('SERVER_PORT', ''),
        'script_name': request.environ.get('SCRIPT_NAME', ''),
        'path_info': request.environ.get('PATH_INFO', ''),
        'query_string': request.environ.get('QUERY_STRING', ''),
        'http_user_agent': request.headers.get('User-Agent', ''),
        'http_accept': request.headers.get('Accept', ''),
        'http_referer': request.headers.get('Referer', ''),
        'http_cookie': request.headers.get('Cookie', ''),
    }

@app.route('/saml/metadata', methods=['GET'])
def metadata():
    settings = OneLogin_Saml2_Settings()
    return settings.get_sp_metadata(), 200, {'Content-Type': 'text/xml'}

@app.route('/saml/login', methods=['POST'])
def login():
    req = prepare_flask_request()
    auth = OneLogin_Saml2_Auth(req, custom_base_path=os.path.join(os.path.dirname(__file__), 'saml'))
    auth.login()
    return '', 302, {'Location': auth.redirect_to()}

@app.route('/saml/acs', methods=['POST'])
def acs():
    req = prepare_flask_request()
    auth = OneLogin_Saml2_Auth(req, custom_base_path=os.path.join(os.path.dirname(__file__), 'saml'))
    auth.process_response()

    if not auth.is_authenticated():
        logging.warning("User not authenticated")
        return jsonify({'error': 'User not authenticated'}), 403

    # Generate SAML response
    response = auth.get_last_response_xml()
    return response, 200, {'Content-Type': 'text/xml'}

if __name__ == '__main__':
    app.run(ssl_context=('path/to/cert.pem', 'path/to/key.pem'))